/**
 * Market benchmarks — the bridge from the Canggu scan to the per-listing audit.
 *
 * `buildBenchmarks` distils the scored scan into a per-cohort record of what the
 * top-quartile (winner) listings measurably do: photo counts, title/description
 * length, the amenities and title words that over-index in winners, pricing, and
 * a few real winner COVER photos to show as visual references. The audit loads
 * this so every recommendation can cite measured Canggu evidence, not guesswork.
 *
 * The static JSON (`benchmarks.greater-canggu.json`) is regenerated by
 * `npm run scan` (and by `writeBenchmarksFile`), so it stays fresh with the market.
 */
import { cohortStats } from "./stats";
import { MARKETS } from "./markets";
import type { ScannedListing } from "./types";
import type { AuditMarketEvidence } from "@/lib/types";
import cangguData from "./benchmarks.greater-canggu.json";
import dubaiData from "./benchmarks.dubai.json";
import londonData from "./benchmarks.london.json";

export interface CoverExample {
  listing_id: string;
  listing_name: string;
  viral_score: number;
  cover_photo_url: string;
  locality: string;
  ttm_revpar: number;
  ttm_occupancy: number;
  rating_overall: number | null;
  num_reviews: number;
}

export interface AmenityEdge {
  amenity: string;
  winner_share: number; // 0..1
  loser_share: number;
  delta: number;
}

export interface MarketBenchmark {
  market: string;
  cohort: string;
  sample_size: number;
  winner_n: number;
  // measured winner medians
  winner_median_photos: number;
  winner_median_title_chars: number;
  winner_median_description_chars: number;
  winner_median_adr_idr: number;
  winner_median_occupancy: number;
  winner_superhost_share: number;
  winner_guest_favorite_share: number;
  // measured loser contrast (for "you vs the market" framing)
  loser_median_photos: number;
  loser_median_description_chars: number;
  loser_instant_book_share: number;
  // what over-indexes in winners
  top_amenities: AmenityEdge[];
  title_keywords: { word: string; delta: number }[];
  /** Native currency of the market's money figures (from markets.ts). */
  currency: string;
  // visual references
  winner_covers: CoverExample[];
}

export type BenchmarksFile = {
  market: string;
  generated_from: number; // sample size
  cohorts: Record<string, MarketBenchmark>;
};

/** 1BR…5+BR — matches the scan's cohort labels. */
export function cohortForBeds(beds: number): string {
  if (beds <= 1) return "1BR";
  if (beds >= 5) return "5+BR";
  return `${beds}BR`;
}

/** Build one benchmark per cohort from a scored scan sample. */
export function buildBenchmarks(market: string, listings: ScannedListing[]): BenchmarksFile {
  const byCohort = new Map<string, ScannedListing[]>();
  for (const l of listings) {
    (byCohort.get(l.cohort) ?? byCohort.set(l.cohort, []).get(l.cohort)!).push(l);
  }

  const cohorts: Record<string, MarketBenchmark> = {};
  for (const [cohort, group] of byCohort) {
    if (group.length < 8) continue; // too small to contrast
    const s = cohortStats(cohort, group);
    // Top 10 of the WHOLE cohort sample, not just the winner quartile (manager
    // ask 2026-07-15): the quartile is 8-9 in Canggu's 33-37-listing cohorts,
    // which capped the list below 10. Quartile stats (medians/contrasts) are
    // unchanged — only the visual winner list draws from the full comp set.
    const winner_covers: CoverExample[] = [...group]
      .filter((l) => l.cover_photo_url)
      .sort((a, b) => b.viral_score - a.viral_score)
      .slice(0, 10)
      .map((l) => ({
        listing_id: l.listing_id,
        listing_name: l.listing_name,
        viral_score: l.viral_score,
        cover_photo_url: l.cover_photo_url!,
        locality: l.locality,
        ttm_revpar: Math.round(l.ttm_revpar),
        ttm_occupancy: l.ttm_occupancy,
        rating_overall: l.rating_overall,
        num_reviews: l.num_reviews,
      }));

    cohorts[cohort] = {
      market,
      cohort,
      currency: MARKETS[market]?.currency ?? "IDR",
      sample_size: s.sample_size,
      winner_n: s.winners.n,
      winner_median_photos: s.winners.median_photos,
      winner_median_title_chars: s.winners.median_title_chars,
      winner_median_description_chars: s.winners.median_description_chars,
      winner_median_adr_idr: Math.round(s.winners.median_adr),
      winner_median_occupancy: s.winners.median_occupancy,
      winner_superhost_share: s.winners.superhost_share,
      winner_guest_favorite_share: s.winners.guest_favorite_share,
      loser_median_photos: s.losers.median_photos,
      loser_median_description_chars: s.losers.median_description_chars,
      loser_instant_book_share: s.losers.instant_book_share,
      top_amenities: s.amenity_edges
        .slice(0, 8)
        .map((e) => ({
          amenity: e.amenity,
          winner_share: e.winners,
          loser_share: e.losers,
          delta: e.delta,
        })),
      title_keywords: s.title_keywords.slice(0, 8).map((k) => ({ word: k.word, delta: k.delta })),
      winner_covers,
    };
  }

  return { market, generated_from: listings.length, cohorts };
}

// --- Load the static per-market benchmarks + shape them for the audit ---

const BENCHMARKS: Record<string, BenchmarksFile> = {
  "greater-canggu": cangguData as unknown as BenchmarksFile,
  dubai: dubaiData as unknown as BenchmarksFile,
  london: londonData as unknown as BenchmarksFile,
};

/** Winner benchmark for a market + bedroom cohort (e.g. "dubai", "3BR"), or null. */
export function getMarketBenchmark(marketKey: string, cohort: string): MarketBenchmark | null {
  return BENCHMARKS[marketKey]?.cohorts[cohort] ?? null;
}

/** Total listings scanned in a market (all cohorts), for "37 of 176" framing. */
export function getMarketScanTotal(marketKey: string): number | null {
  return BENCHMARKS[marketKey]?.generated_from ?? null;
}

/**
 * Shape a benchmark into the evidence stored on an audit + fed to the scorer:
 * the measured winner-vs-loser facts plus the winner cover examples the report
 * shows as visual references.
 */
export function toAuditEvidence(b: MarketBenchmark): AuditMarketEvidence {
  return {
    market: b.market,
    cohort: b.cohort,
    sample_size: b.sample_size,
    winner_median_photos: b.winner_median_photos,
    loser_median_photos: b.loser_median_photos,
    winner_median_title_chars: b.winner_median_title_chars,
    winner_median_description_chars: b.winner_median_description_chars,
    loser_median_description_chars: b.loser_median_description_chars,
    winner_median_adr_idr: b.winner_median_adr_idr,
    winner_median_occupancy: b.winner_median_occupancy,
    winner_superhost_share: b.winner_superhost_share,
    winner_guest_favorite_share: b.winner_guest_favorite_share,
    top_amenities: b.top_amenities.map((a) => ({
      amenity: a.amenity,
      winner_share: a.winner_share,
      loser_share: a.loser_share,
    })),
    title_keywords: b.title_keywords.map((k) => k.word),
    currency: b.currency,
    winner_covers: b.winner_covers,
  };
}

/** Landing-page trust stats, computed from the real scan data (never hardcode). */
export function getTrustStats(): { listings: number; markets: string[] } {
  const files = Object.values(BENCHMARKS);
  return {
    listings: files.reduce((sum, f) => sum + (f.generated_from ?? 0), 0),
    markets: files.map((f) => MARKETS[f.market]?.title ?? f.market),
  };
}
